// W5 — Build Input
// Edita los valores de `input` para probar distintos payloads.
//
// CONVENCIONES DEV:
//   - canal y id_evento solo se usan para id_evento_dev (trazabilidad de pruebas)
//   - W5 NO genera idempotency_key. La función cancelar_prereserva() no la espera.
//     Tampoco implementa idempotent_match: re-cancelar una pre-reserva ya
//     terminal devuelve error 'estado_no_cancelable'.
//   - source_event fijo: "n8n_w05_cancelar_prereserva_manual"
//
// MOTIVOS VÁLIDOS (enum implícito en la función):
//   - "cliente" -> pre-reserva pasa a 'cancelada_por_cliente'
//   - "bloqueo" -> pre-reserva pasa a 'cancelada_por_bloqueo'
//   Cualquier otro valor (incluido "" o null) rebota con error 'motivo_invalido'.
//
// EFECTO SOBRE PAGOS ASOCIADOS:
//   La función NO modifica pagos. Solo los cuenta y los reporta en el output.
//   Si una pre-reserva tiene pagos asociados al momento de cancelar, esos pagos
//   quedan "huérfanos" tras la cancelación, esperando decisión humana (reembolso,
//   anulación, etc.). El reembolso real es trabajo de un workflow operativo aparte.

// === EDITAR ESTOS VALORES PARA CADA PRUEBA ===
const input = {
  // Identificación del evento (solo para trazabilidad de pruebas)
  canal: "manual_dev",
  id_evento: "test_w05_001",

  // Obligatorio (debe corresponder a una pre-reserva en estado pendiente_pago o pago_en_revision)
  id_pre_reserva: 0,  // ← reemplazar por el ID de la pre-reserva nueva creada con W2 (Test 0)

  // Motivo (obligatorio): "cliente" o "bloqueo"
  motivo: "cliente",

  // Descripción libre (opcional, queda en log_cambios)
  descripcion: "Cliente cancela por cambio de planes - test W5 happy path"
};
// =============================================

return [{ json: input }];

// W5 — Build Payload
// Toma el input editable de Build Input y construye:
//   1. source_event (convención 6C v1.2 Sección 5.5):
//        n8n_w05_cancelar_prereserva_manual
//   2. id_evento_dev: solo para trazabilidad de pruebas en el wrapper
//      (NO se manda a la función SQL).
//   3. payload JSONB según contrato de cancelar_prereserva(jsonb).
//
// CONTRATO PAYLOAD:
//   Obligatorios: id_pre_reserva, motivo, source_event
//   Opcionales:   descripcion (texto libre que queda en log_cambios)
//
// W5 NO genera idempotency_key. La función no la espera ni implementa
// idempotent_match (mismo patrón que confirmar_reserva).
//
// NORMALIZACIÓN DEFENSIVA (continuación de patrón W3/W4):
// Aplicamos nv() a todos los campos incluyendo los obligatorios.
// La función cancelar_prereserva() no aplica NULLIF en sus extracts;
// mientras el hardening SQL no se aplique (ver Pendiente_pre_produccion.md),
// la defensa queda en n8n.
//
// Caso especial 'motivo': si viene como "" se manda como null, lo cual la
// función detecta como payload_invalido en lugar de motivo_invalido. Es OK:
// ambos son errores de payload mal armado, no de negocio.

const input = $input.first().json;

const source_event = 'n8n_w05_cancelar_prereserva_manual';
const id_evento_dev = `${input.canal}_${input.id_evento}`;

const nv = (v) => (v === '' || v === undefined ? null : v);

const payload = {
  // Obligatorios (con normalización defensiva)
  id_pre_reserva: nv(input.id_pre_reserva),
  motivo: nv(input.motivo),
  source_event,

  // Opcionales
  descripcion: nv(input.descripcion)
};

return [{
  json: {
    payload,
    source_event,
    id_evento_dev,
    input  // se preserva para trazabilidad en Build Response
  }
}];

// W5 — Build Response
// Interpreta el JSONB que devuelve cancelar_prereserva() y arma el wrapper externo.
//
// Contrato de salida de la función:
//   - happy: { ok: true, id_pre_reserva, estado_anterior, estado_nuevo,
//              pagos_asociados_count, pagos_asociados_ids }
//   - error: { ok: false, error: '<codigo>', ...detalle }
//
// CONVENCIONES DEL WRAPPER:
//   - ok = resultado.ok
//   - error solo se llena cuando resultado.ok = false
//   - id_evento_dev para trazabilidad de pruebas
//   - result siempre lleva el JSONB completo de la función
//
// W5 NO incluye idempotency_key (no aplica) ni warning (la función no
// emite warnings — re-cancelar devuelve error "estado_no_cancelable").

const buildPayload = $('Build Payload').first().json;
const pgItem = items[0]?.json;
const resultado = pgItem?.resultado;

if (!resultado || typeof resultado !== 'object') {
  return [{
    json: {
      ok: false,
      workflow: 'vita_w05_cancelar_prereserva_supabase',
      source_event: buildPayload.source_event,
      id_evento_dev: buildPayload.id_evento_dev,
      error: 'sin_respuesta_de_funcion',
      result: null,
      executed_at: new Date().toISOString()
    }
  }];
}

const ok = resultado.ok === true;

return [{
  json: {
    ok,
    workflow: 'vita_w05_cancelar_prereserva_supabase',
    source_event: buildPayload.source_event,
    id_evento_dev: buildPayload.id_evento_dev,
    error: ok ? null : (resultado.error || 'error_desconocido'),
    result: resultado,
    executed_at: new Date().toISOString()
  }
}];
